# 当 prompt 不够长时自动重复拼接到目标长度
PROMPT_TOKENS=${PROMPT_TOKENS:-3000}  # >0 时截取前 N 个 token
PROMPT_REPEAT=${PROMPT_REPEAT:-1}     # 重复拼接次数（设大值可测长序列）
if [ "$PROMPT_REPEAT" -gt 1 ]; then
    ORIG_PROMPT="$PROMPT"
    PROMPT=""
    for ((r = 0; r < PROMPT_REPEAT; r++)); do
        PROMPT="${PROMPT}${ORIG_PROMPT} "
    done
fi
MAX_NEW_TOKENS=${MAX_NEW_TOKENS:-200}
NUM_PREFILL_REQUESTS=${NUM_PREFILL_REQUESTS:-0}  # 在真正比对前先跑 N 个 dummy 请求（测跨请求状态泄露）
SGLANG_TP=1
SGLANG_MAX_TOTAL_TOKENS=131072
SGLANG_PAGE_SIZE=64
SGLANG_CHUNKED_PREFILL_SIZE=${SGLANG_CHUNKED_PREFILL_SIZE:-8192}  # 设小值(如1024)可测 chunked prefill
TOP_K=1000

# Python 路径
VEOMNI_PYTHON="/root/VeOmni/.venv/bin/python"
SGLANG_PYTHON="/root/sglang/python/.venv/bin/python"

# GPU
pkill -f "burner.*--gpu 0" || true
export CUDA_VISIBLE_DEVICES=0

# 工作目录
WORK_DIR="/apdcephfs_tj5/share_300719894/user/guhao/InfiniteLongLM"
SCRIPT_DIR="$WORK_DIR/code_exp"
SGLANG_PYTHONPATH="/apdcephfs_tj5/share_300719894/user/guhao/SGLang-HSA/python"
# =====================================================

# 日志和临时文件
task_id=$(date +%Y%m%d_%H%M%S)
RUN_DIR="$(pwd)"
log_dir="$RUN_DIR/outerr_sglang"
mkdir -p "$log_dir"
out_file="$log_dir/verify_${task_id}.out"

export PYTHONUNBUFFERED=1

# VOCAB_DIR 默认值
if [ -z "$VOCAB_DIR" ]; then
    VOCAB_DIR="$CHECKPOINT_PATH"
fi

# 临时目录存放 config.json 和 pickle 结果
TMP_DIR=$(mktemp -d /tmp/verify_hsa_XXXXXX)
CONFIG_JSON="$TMP_DIR/config.json"
HF_OUTPUT="$TMP_DIR/hf_results.pkl"
SG_OUTPUT="$TMP_DIR/sglang_results.pkl"

# 生成配置 JSON（用 Python 安全处理 PROMPT 中的特殊字符）
PROMPT_FILE="$TMP_DIR/prompt.txt"
cat > "$PROMPT_FILE" <<'PROMPT_EOF'
PROMPT_PLACEHOLDER
PROMPT_EOF
# 用实际 PROMPT 内容覆盖（heredoc 用单引号包裹避免变量展开，所以这里用 printf）
printf '%s' "$PROMPT" > "$PROMPT_FILE"

python3 -c "
import json, sys
prompt = open('$PROMPT_FILE', 'r').read()
cfg = {
    'checkpoint_path': '$CHECKPOINT_PATH',
    'vocab_dir': '$VOCAB_DIR',
    'device': '$DEVICE',
    'prompt': prompt,
    'max_new_tokens': $MAX_NEW_TOKENS,
    'sglang_tp': $SGLANG_TP,
    'sglang_max_total_tokens': $SGLANG_MAX_TOTAL_TOKENS,
    'sglang_page_size': $SGLANG_PAGE_SIZE,
    'sglang_chunked_prefill_size': $SGLANG_CHUNKED_PREFILL_SIZE,
    'top_k': $TOP_K,
    'num_prefill_requests': $NUM_PREFILL_REQUESTS,
    'prompt_tokens': $PROMPT_TOKENS,
    'hf_output_path': '$HF_OUTPUT',
    'sglang_output_path': '$SG_OUTPUT',
}
with open('$CONFIG_JSON', 'w') as f:
    json.dump(cfg, f, indent=2, ensure_ascii=False)
print(f'[Config] JSON written: $CONFIG_JSON ({len(prompt)} chars prompt)')
"

# 开始记录
{
echo "========================================"
echo "SGLang vs HF 一致性验证"
echo "开始时间: $(date)"
echo "CUDA_VISIBLE_DEVICES: $CUDA_VISIBLE_DEVICES"
echo "临时目录: $TMP_DIR"
echo "配置: $CONFIG_JSON"
echo "========================================"
echo ""

# Step 1: HF 推理（veomni 环境）
echo ">>> [Step 1/3] HF Transformers 推理 (veomni 环境)"
echo "    Python: $VEOMNI_PYTHON"
echo "    SKIP_MLP: ${SKIP_MLP:-0}"
echo "    NUM_LAYERS: ${NUM_LAYERS:-0}"
echo "    ONLY_LAYERS: ${ONLY_LAYERS:-}"
echo "========================================" 
SKIP_MLP="${SKIP_MLP:-0}" NUM_LAYERS="${NUM_LAYERS:-0}" ONLY_LAYERS="${ONLY_LAYERS:-}" $VEOMNI_PYTHON "$SCRIPT_DIR/verify_hf_worker.py" "$CONFIG_JSON" 2>&1
echo ""

# Step 2: SGLang 推理（sglang 环境）
echo ">>> [Step 2/3] SGLang Engine 推理 (sglang 环境)"
echo "    Python: $SGLANG_PYTHON"
echo "    SKIP_MLP: ${SKIP_MLP:-0}"
echo "    NUM_LAYERS: ${NUM_LAYERS:-0}"
echo "    ONLY_LAYERS: ${ONLY_LAYERS:-}"
echo "========================================"
PYTHONPATH="$SGLANG_PYTHONPATH:${PYTHONPATH:-}" SGLANG_HSA_DEBUG=0 SGLANG_ENABLE_STRICT_MEM_CHECK_DURING_IDLE=0 SKIP_MLP="${SKIP_MLP:-0}" NUM_LAYERS="${NUM_LAYERS:-0}" ONLY_LAYERS="${ONLY_LAYERS:-}" \
    $SGLANG_PYTHON "$SCRIPT_DIR/verify_sglang_worker.py" "$CONFIG_JSON" 2>&1
echo ""

# Step 3: 对比结果（用 sglang 环境的 python，它有 torch + transformers）
echo ">>> [Step 3/3] 对比结果"
echo "========================================"
$SGLANG_PYTHON "$SCRIPT_DIR/verify_sglang_vs_hf.py" "$CONFIG_JSON" 2>&1
echo ""

echo "========================================"
echo "结束时间: $(date)"
echo "========================================"
} >> "$out_file" 2>&1

# 清理临时文件
rm -rf "$TMP_DIR"

echo "验证完成！输出日志: $out_file"

